      "content": "const _ = require('lodash');
const db = require('../../db');

async function listProblems({ limit, difficulty, tags, includeComponents }) {
  // Base query to fetch problems with optional filters
  let query = db('problems').select('*');

  if (difficulty) {
    query = query.where('difficulty', difficulty);
  }

  if (tags && tags.length > 0) {
    query = query.whereRaw('tags @> ?', [tags]);
  }

  // Apply limit
  if (limit) {
    query = query.limit(limit);
  }

  const problems = await query;

  if (!includeComponents) {
    return { problems };
  }

  // When includeComponents=true, we need to add componentLanguageTotals and componentStatusTotals
  // for the filtered and limited problems only.

  // Extract problem ids from filtered and limited problems
  const problemIds = problems.map(p => p.id);

  // Fetch components for these problems
  const components = await db('components').whereIn('problemId', problemIds);

  // Aggregate language totals and status totals
  const componentLanguageTotals = {};
  const componentStatusTotals = {};

  for (const comp of components) {
    // Language totals
    if (!componentLanguageTotals[comp.language]) {
      componentLanguageTotals[comp.language] = 0;
    }
    componentLanguageTotals[comp.language]++;

    // Status totals
    if (!componentStatusTotals[comp.status]) {
      componentStatusTotals[comp.status] = 0;
    }
    componentStatusTotals[comp.status]++;
  }

  return {
    problems,
    componentLanguageTotals,
    componentStatusTotals
  };
}

module.exports = {
  listProblems
};
